previewCss:
.darma-loader-darma-custom-419 {color: var(--loader-color, #7c3aed);
  --loader-secondary-color: var(--loader-secondary-color, #c084fc);
  --loader-bg: var(--loader-bg, #ffffff);
  width: 50px;
  aspect-ratio: 1;
  display: grid;
}.darma-loader-darma-custom-419::before,.darma-loader-darma-custom-419::after{content: "";
  grid-area: 1/1;
  border-radius: 50%;
  background: repeating-conic-gradient(#0000,currentColor 1deg 18deg,#0000 20deg 36deg);
  -webkit-mask: repeating-radial-gradient(farthest-side,currentColor 0 10%,#0000 0 20%);
  animation: darma-loader-darma-custom-419-l10 4s infinite linear;
}.darma-loader-darma-custom-419::after{-webkit-mask: repeating-radial-gradient(farthest-side,#0000 0 10%,currentColor 0 20%);
  animation-direction: reverse;
}@keyframes darma-loader-darma-custom-419-l10 {100% {transform: rotate(.5turn)}}

